// ============================================================
// EXTRACTDATA v13.4 - WF1 2-STEP APPROVAL WITH PSYCHOLOGY
// ============================================================
// Purpose: Extract and validate clarification data for email workflow
// Mode: Run Once for All Items
// Version: 13.4 - Same as 13.3, no changes needed
// ============================================================

const items = $input.all();
const results = [];

const ALWAYS_CC = ['hoangkha@esuhai.com', 'vynnl@esuhai.com'];

function safeText(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return '';
  return arr.map(t => t.plain_text || '').join('');
}

function safeSelect(select) {
  if (!select || !select.name) return '';
  return select.name;
}

function safeDate(date) {
  if (!date || !date.start) return '';
  return date.start;
}

function safeRelation(relation) {
  if (!Array.isArray(relation) || relation.length === 0) return null;
  return relation[0];
}

function safeRollup(rollup) {
  if (!rollup || rollup.type !== 'array' || !Array.isArray(rollup.array)) return '';
  if (rollup.array.length === 0) return '';
  const firstItem = rollup.array[0];
  if (firstItem.type === 'email') return firstItem.email || '';
  if (firstItem.type === 'rich_text') return safeText(firstItem.rich_text);
  return '';
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const page = item.json;
  const props = page.properties || {};

  const id = page.id;
  const tieuDe = safeText(props['Tiêu đề']?.title);
  const nguon = safeSelect(props['Nguồn']?.select);
  const ngayNhan = safeDate(props['Ngày nhận']?.date);
  const noiDung = safeText(props['Nội dung gốc']?.rich_text);

  const tinhTrang = safeSelect(props['TÌNH TRẠNG']?.select);
  const daDuyet = safeSelect(props['✅ Đã duyệt bởi người chỉ đạo']?.select);
  const lenhGuiLoiNhac = safeSelect(props['LỆNH GỬI LỜI NHẮC']?.select);

  const nguoiChiDaoRelation = safeRelation(props['Người chỉ đạo']?.relation);
  const emailNguoiChiDao = safeRollup(props['Email người chỉ đạo']?.rollup);
  const tenNguoiChiDao = safeText(props['Tên người chỉ đạo']?.rollup?.array?.[0]?.title || []);

  const dauMoiRelation = safeRelation(props['T1 - ĐẦU MỐI']?.relation);
  const emailDauMoi = safeRollup(props['Email đầu mối']?.rollup);
  const tenDauMoi = safeText(props['Tên đầu mối']?.rollup?.array?.[0]?.title || []);

  const t2NhiemVu = safeText(props['T2 - NHIỆM VỤ']?.rich_text);
  const t3ChiTieu = safeText(props['T3 - CHỈ TIÊU']?.rich_text);
  const t4ThoiHan = safeDate(props['T4 - THỜI HẠN']?.date);

  if (!emailNguoiChiDao || emailNguoiChiDao === '') {
    results.push({
      json: {
        clarificationId: id,
        warning: true,
        error: 'MISSING_NGUOI_CHI_DAO',
        message: `[${tieuDe}] Thiếu Email người chỉ đạo`,
        tieuDe,
        tinhTrang,
        daDuyet,
        logStatus: '⚠️ Warning',
        logError: 'Missing: Email người chỉ đạo',
        logDetails: `ID: ${id}, Title: ${tieuDe}`,
        sendTo: '',
        emailSubject: '',
        url: page.url,
        version: '13.4'
      }
    });
    continue;
  }

  let step = '';
  let sendTo = '';
  let emailSubject = '';
  let ccTo = [];

  if (!daDuyet || daDuyet === '' || daDuyet === 'Chưa duyệt') {
    step = 'STEP1';
    sendTo = emailNguoiChiDao;
    emailSubject = `[Cần Duyệt] ${tieuDe || 'Chỉ đạo mới'}`;
    ccTo = ALWAYS_CC.filter(e => e !== sendTo);

  } else if (daDuyet === 'Đã duyệt') {
    if (!emailDauMoi || emailDauMoi === '') {
      results.push({
        json: {
          clarificationId: id,
          warning: true,
          error: 'MISSING_DAU_MOI',
          message: `[${tieuDe}] Thiếu Email đầu mối`,
          tieuDe,
          emailNguoiChiDao,
          tenNguoiChiDao,
          tinhTrang,
          daDuyet,
          logStatus: '⚠️ Warning',
          logError: 'Missing: Email đầu mối',
          logDetails: `ID: ${id}, Title: ${tieuDe}`,
          sendTo: '',
          emailSubject: '',
          url: page.url,
          version: '13.4'
        }
      });
      continue;
    }

    step = 'STEP2';
    sendTo = emailDauMoi;
    emailSubject = `[Cần Làm Rõ] ${tieuDe || 'Chỉ đạo'} - Hạn: ${t4ThoiHan || 'Chưa xác định'}`;

    const ccList = new Set(ALWAYS_CC);
    if (emailNguoiChiDao) ccList.add(emailNguoiChiDao);
    ccList.delete(sendTo);
    ccTo = Array.from(ccList);

  } else {
    continue;
  }

  results.push({
    json: {
      clarificationId: id,
      step,
      tieuDe,
      nguon,
      ngayNhan,
      noiDung,
      emailNguoiChiDao,
      tenNguoiChiDao,
      emailDauMoi,
      tenDauMoi,
      sendTo,
      emailSubject,
      ccTo: ccTo.join(', '),
      tinhTrang,
      daDuyet,
      lenhGuiLoiNhac,
      t2NhiemVu,
      t3ChiTieu,
      t4ThoiHan,
      url: page.url,
      version: '13.4'
    }
  });
}

return results;

return items.map(item => {
  const data = item.json;

  let status = "⚠️ Warning";

  if (data.sendTo && data.emailSubject && data.clarificationId) {
    status = "✅ Success";
  }

  if (data.logStatus) {
    status = data.logStatus;
  }

  const body = {
    parent: { database_id: "53a48a4f29ba46d28e533f358d3c513c" },
    properties: {
      "Log": { 
        title: [{ 
          text: { 
            content: `WF1 - ${data.step || 'No step'}` 
          } 
        }] 
      },
      "Workflow": { 
        select: { 
          name: "WF1 - Gửi email" 
        } 
      },
      "Status": { 
        select: { 
          name: status
        } 
      },
      "Clarification": { 
        relation: data.clarificationId ? [{ id: data.clarificationId }] : [] 
      },
      "Details": { 
        rich_text: [{ 
          text: { 
            content: data.logDetails || 
                     data.message || 
                     `ID: ${data.clarificationId}\nTitle: ${data.tieuDe}\nTo: ${data.sendTo || 'N/A'}\nSubject: ${data.emailSubject || 'N/A'}` || 
                     "No details"
          } 
        }] 
      }
    }
  };

  if (data.sendTo) {
    body.properties["Email To"] = { email: data.sendTo };
  }

  return { json: body };
});

